import torch, numpy as np
ckpt=torch.load('checkpoints/hotspot_esm_ensemble.pt', map_location='cpu', weights_only=False)
meta=ckpt.get('meta',{})
print('meta_keys', sorted(meta.keys()))
for k in ['ensemble_weights','esm_input_dim','hot_start','hot_end','wt_sequence','wildtype_sequence']:
    print(k, type(meta.get(k)).__name__, meta.get(k) if k!='wt_sequence' else ('len='+str(len(meta.get(k))) if isinstance(meta.get(k),str) else None))
for name in ['mlp_state_dict','cnn_state_dict','dilated_cnn_state_dict','esm_head_state_dict']:
    sd=ckpt.get(name)
    if sd:
        print('\n',name)
        for kk,v in sd.items():
            print(kk, tuple(v.shape) if hasattr(v,'shape') else type(v))
            break
        if name=='esm_head_state_dict':
            for kk,v in sd.items():
                print('esm',kk, tuple(v.shape) if hasattr(v,'shape') else type(v))

for path in ['cache/esm_t12_train.npy','cache/esm_t12_val.npy']:
    arr=np.load(path, mmap_mode='r')
    print(path, arr.shape, arr.dtype, 'firstrow_mean', float(arr[0].mean()))
